var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"……후훗.","JPN":"……ふふっ。","ENG":"...Fuu fuu.","TWN":"……呵呵。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그런 말을 면전에서 듣게 되리라고는 예상 못했습니다.","JPN":"そのような言葉を面と向かって聞くことになるとは思ってもみませんでした。","ENG":"I did not expect you to say that right to my face.","TWN":"沒想到你會面對面說出這樣的話。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"제 진심을 알고 싶다니, 의외로 서정적인 취향이었군요. 브레히트 중사.","JPN":"私の本心が知りたいだなんて、意外とロマンチストなのですね。ブレヒト軍曹。","ENG":"You want to know what I truly think? What poetic taste you have, Sergeant Brecht.","TWN":"想知道我的真心嗎？沒想到你如此詩情畫意，布萊希特中士。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"저는 그림자입니다.","JPN":"私はシャドウです。","ENG":"I am a Shadow.","TWN":"我是暗影。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그 중에서도 당신들의 기준으로는 아득한 시간을 지내 온 그림자이지요.","JPN":"その中でも、あなたたちの基準では遥かに長い時間を過ごしてきたシャドウなのです。","ENG":"A Shadow who has spent eons in your terms, as a matter of fact.","TWN":"我經歷過的歲月可能遠超你們人類的想像。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"20년 남짓한 시간이라고 해도, 제 의식에는 한순간 일어난 잔물결에 지나지 않습니다.","JPN":"20年余りの時間と言えども、私の意識の中ではほんの一瞬に過ぎません。","ENG":"Even if 20 or so years have passed, they are mere ripples within my consciousness.","TWN":"20年的時間，對我來說也不過是曇花一現。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그런데도 당신은 저에게 그 순간만을 찾는군요.","JPN":"なのに、あなたは私からその瞬間だけを探しているのですね。","ENG":"And yet, you only seem to want to see that moment from me.","TWN":"而你卻始終不曾放棄尋找對於我而言只是一瞬間的時光。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"그야 당연하죠. 레버넌트 씨. 다른 사람들은 몰라도 전 알고 있거든요.","JPN":"そりゃ当たり前ですよ、レヴナントさん。他の人ならともかく、私は知ってるんです。","ENG":"Of course, Revenant. Others may not know, but I know you.","TWN":"那當然，亡靈，因為我比任何人都清楚。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"귀관의 공헌에 감사합니다.","JPN":"貴官の貢献に感謝します。","ENG":"Thank you for all you’ve done.","TWN":"謝謝中士的貢獻。"},"stage":{"bg":"HARMONY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"귀관이 아니었으면…… 이 풍경은 볼 수 없었을 겁니다.","JPN":"貴官がいなかったら……この景色を見ることは叶いませんでした。","ENG":"If it weren’t for you... We never would have been able to witness this moment.","TWN":"因為中士……才能看到這樣的場景。"},"stage":{"bg":"HARMONY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"레버넌트 씨에게 가장 소중한 시간은, 그 순간 속에 있었다는 걸.","JPN":"レヴナントさんにとって一番大切な時間は、その瞬間にあったってこと。","ENG":"I know that those are the most precious moments for you, Revenant.","TWN":"亡靈最珍貴的時間，就在那一瞬間的時光裡。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"아주머니를 살해하고…. 저에게는 확실히 손을 쓰지 않은 이유도 그래서였겠죠.","JPN":"おばさんを殺した後で……私を殺そうとしないのもそういう理由からでしょう。","ENG":"It's also why you murdered Madam Schneider... and haven't done anything to me yet.","TWN":"所以你才會在殺害伯母後……沒有對我下毒手。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"얼마든지 도려낼 수 있을 줄 알았는데, 사실은 그렇지 않다는 걸.","JPN":"いくらでも捨てられると思っていたのに、実はそうじゃなかったんです。","ENG":"You thought you could just remove it anytime you wanted to. But in truth, you can't.","TWN":"你以為可以抹除那份記憶，其實你辦不到。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"……고집스럽군요. 브레히트 중사.","JPN":"……しつこいですね。ブレヒト軍曹。","ENG":"...You are stubborn, Sergeant Brecht.","TWN":"……你真固執，布萊希特中士。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"당연하죠. 어떤 기분인지는 직접 겪어 봐서 알거든요.","JPN":"もちろんです。どんな気分かは、私が直接経験してわかってますから。","ENG":"Of course. I know exactly how you feel because I've been there too.","TWN":"當然，因為我親身體會過。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"지긋지긋했던 가족들이 잃고 나서 돌아보니 생각보다 소중했다거나.","JPN":"うんざりしていた家族を失ってみたら、思ったより大切に思っていたんだって気付いたとか。","ENG":"Looking back and realizing how invaluable family is, only after losing them.","TWN":"失去親人後才會發現，那些令你厭倦的人其實比你想像中更加珍貴。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"남들은 흘려들을 수도 있는 고맙다는 말 한마디 때문에, 코가 꿰인다거나.","JPN":"他の人は聞き流すであろう感謝の一言のせいで逃げ出せなくなるとか。","ENG":"Freezing up whenever someone says \\"thank you\\" when others take it for granted.","TWN":"也會因為聽到一句致謝的話語，一直放不下那個人。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"그래서 쫓아왔어요. 당신에게 전할 말이 있거든요.","JPN":"それで追ってきました。あなたに伝えたい言葉があるんです。","ENG":"That's why I came. Because I have something to say to you.","TWN":"所以我才會追你到這裡，我有話對你說。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"레버넌트 씨.","JPN":"レヴナントさん。","ENG":"Revenant.","TWN":"亡靈。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"……그렇다면, 우선은 그 레버넌트부터 찾아내야겠군요.","JPN":"……それなら、まずはそのレヴナントから探し出さないといけませんね。","ENG":"...Then, perhaps you should find this Revenant person.","TWN":"……這麼說，你得先找出那個亡靈。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"물론 그리 쉽지는 않을 겁니다, 브레히트 중사.","JPN":"もちろんそう簡単にはさせません、ブレヒト軍曹。","ENG":"It will not be so easy, Sergeant Brecht.","TWN":"不會那麼容易的，布萊希特中士。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"여기서라면, 제 음악이 아우르는 영역은─","JPN":"ここなら、私の音楽がカバーできる領域は──","ENG":"Because here, my music envelops the–","TWN":"在這裡，我的音樂可以包容整個─"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"─충격파가, 제 조율을 망가뜨린 건가요?","JPN":"──衝撃波が調律を壊した？","ENG":"–Did your shockwave just... ruin my tuning?","TWN":"——衝擊波打亂了我的調音？"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"순수한 물리력만으로 영향을 줄 정도라면…. 무척 위력적이군요.","JPN":"純粋な物理力だけで影響を与えたというなら……すさまじい威力ですね。","ENG":"Being able to affect it by pure physical force... How formidable.","TWN":"只靠純粹的物理力量就能造成這樣的影響……很驚人的威力。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"작정하고 싸우는 게 좋을 걸요, 레버넌트 씨.","JPN":"真剣に戦った方がいいですよ、レヴナントさん。","ENG":"You better fight like you mean it, Revenant.","TWN":"我勸你做好覺悟，亡靈。"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"당신이 얼마나 위험한 적인지는 알고 있지만….","JPN":"どれほど危険な敵か知っていても……","ENG":"I know how dangerous of an enemy you are, but...","TWN":"即使明白你是一個極度危險的敵人……"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"저는…. 당신 한 명에게 닿기만을 바라고 왔으니까!","JPN":"私は……あなた一人に届くことだけを願ってここまで来たんですから！","ENG":"I... came all the way here hoping to reach out to you!","TWN":"但是我……還是為了見你而義無反顧地來到這裡！"},"stage":{"bg":"SKY_SUNSET","bgm":"UNBREAKABLE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};